const source = ($json.body && Object.keys($json.body).length ? $json.body : $json.query) || {};
const uniqueSuffix = `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
const rawSessionId = (source.sessionId || '').trim();
const rawMessageId = (source.messageId || '').trim();
const userId = (source.userId || '').trim();
const chatInput = String(source.chatInput || '').trim();
const sessionId = rawSessionId || `adhoc-session-${uniqueSuffix}`;
const messageKey = rawMessageId || uniqueSuffix;
const runId = `owui-run-${messageKey}`;
const eventId = `owui-event-${messageKey}`;
const occurredAt = new Date().toISOString();

return [{
  json: {
    chat_input: chatInput,
    user_id: userId,
    session_id: sessionId,
    message_id: rawMessageId,
    run_id: runId,
    event_id: eventId,
    idempotency_key: `openwebui:${messageKey}`,
    occurred_at: occurredAt,
    node_id: 'prototype-local-openwebui',
    node_role: 'openwebui.pipe',
    display_name: 'Prototype Local Open WebUI Pipe',
    surface: 'openwebui',
    metadata_json: {
      source: 'openwebui.pipe',
      webhook_path: 'prototype-postgres-tables',
      user_id: userId,
      raw_session_id: rawSessionId || null,
      raw_message_id: rawMessageId || null
    }
  }
}];
